func examDashboardCount(stats *dto.ExamDashboardStats, kind string) string {
	if stats == nil {
		return "0"
	}
	switch kind {
	case "active":
		return strconv.FormatInt(stats.ActiveExams, 10)
	case "published":
		return strconv.FormatInt(stats.PublishedResults, 10)
	case "passed":
		return strconv.FormatInt(stats.StudentsPassed, 10)
	case "failed":
		return strconv.FormatInt(stats.StudentsFailed, 10)
	}
	return "0"
}

